  private _get625RiskProgress(): number {
    return Math.round(this._625RiskAssessmentWorkflow.filter(s => s.status === 'completed').length / this._625RiskAssessmentWorkflow.length * 100);
  }

  private _get625TreatmentSummary(): {total: number; approved: number; avgReduction: number; investment: string} {
    const a = this._625TreatmentOptions.filter(r => r.status === 'approved').length;
    const avg = this._625TreatmentOptions.reduce((s, r) => s + ((r.before - r.after) / r.before * 100), 0) / this._625TreatmentOptions.length;
    return {total: this._625TreatmentOptions.length, approved: a, avgReduction: Math.round(avg), investment: '$1.125M annually'};
  }

  private _get625RuleSummary(): {total: number; passing: number; failing: number; avgRate: number; violations: number} {
    const p = this._625ComplianceRules.filter(r => r.result === 'pass').length;
    const f = this._625ComplianceRules.filter(r => r.result === 'fail').length;
    const avg = this._625ComplianceRules.reduce((s, r) => s + r.passRate, 0) / this._625ComplianceRules.length;
    const v = this._625ComplianceRules.reduce((s, r) => s + r.violations, 0);
    return {total: this._625ComplianceRules.length, passing: p, failing: f, avgRate: Math.round(avg * 10) / 10, violations: v};
  }

  private _get625PipelineStats(): {positions: number; applicants: number; interviewing: number; offers: number; critical: number} {
    const t = this._625TalentPositions.length;
    const a = this._625TalentPositions.reduce((s, p) => s + p.applicants, 0);
    const i = this._625TalentPositions.reduce((s, p) => s + p.interviews, 0);
    const o = this._625TalentPositions.reduce((s, p) => s + p.offers, 0);
    const c = this._625TalentPositions.filter(x => x.urgency === 'critical').length;
    return {positions: t, applicants: a, interviewing: i, offers: o, critical: c};
  }

