  private _getz625ScenarioSummary(): {total: number; critical: number; high: number; drilled: number; avgRiskScore: number} {
    const crit = this._z625IncidentScenarios.filter(s => s.impact === 'Critical').length;
    const high = this._z625IncidentScenarios.filter(s => s.impact === 'High').length;
    const avg = this._z625IncidentScenarios.reduce((s, x) => s + x.riskScore, 0) / this._z625IncidentScenarios.length;
    return {total: this._z625IncidentScenarios.length, critical: crit, high: high, drilled: this._z625IncidentScenarios.length, avgRiskScore: Math.round(avg)};
  }

  private _getz625VendorRiskSummary(): {total: number; approved: number; conditional: number; remediation: number; avgScore: number} {
    const approved = this._z625ThirdPartyRiskData.filter(v => v.status === 'approved').length;
    const cond = this._z625ThirdPartyRiskData.filter(v => v.status === 'conditional').length;
    const rem = this._z625ThirdPartyRiskData.filter(v => v.status === 'remediation_required').length;
    const avg = this._z625ThirdPartyRiskData.reduce((s, v) => s + v.riskScore, 0) / this._z625ThirdPartyRiskData.length;
    return {total: this._z625ThirdPartyRiskData.length, approved, conditional: cond, remediation: rem, avgScore: Math.round(avg)};
  }

  private _getz625TrainingSummary(): {total: number; avgCompletion: number; avgScore: number; overdueUpdates: number} {
    const avgComp = this._z625SecurityTrainingCatalog.reduce((s, t) => s + t.completionRate, 0) / this._z625SecurityTrainingCatalog.length;
    const avgScore = this._z625SecurityTrainingCatalog.filter(t => t.avgScore > 0).reduce((s, t) => s + t.avgScore, 0) / this._z625SecurityTrainingCatalog.filter(t => t.avgScore > 0).length;
    return {total: this._z625SecurityTrainingCatalog.length, avgCompletion: Math.round(avgComp * 10) / 10, avgScore: Math.round(avgScore), overdueUpdates: 0};
  }

  private _getz625ToolHealthSummary(): {total: number; healthy: number; degraded: number; annualCost: string} {
    const healthy = this._z625SecurityToolInventory.filter(t => t.health === 'healthy').length;
    const degraded = this._z625SecurityToolInventory.filter(t => t.health === 'degraded').length;
    const cost = this._z625SecurityToolInventory.reduce((s, t) => s + parseInt(t.annualCost.replace(/[^0-9]/g, '')), 0);
    return {total: this._z625SecurityToolInventory.length, healthy, degraded, annualCost: '$' + (cost / 1000).toFixed(0) + 'K'};
  }


